const listMinerStateSnapshots = `-- name: ListMinerStateSnapshots :many
SELECT
    dd.device_identifier,
    COALESCE(d.mac_address, '') as mac_address,
    d.serial_number,
    dd.model,
    dd.manufacturer,
    dd.firmware_version,
    d.worker_name,
    ds.status as device_status,
    ds.status_timestamp,
    ds.status_details,
    dd.ip_address,
    dd.port,
    dd.url_scheme,
    CASE WHEN d.id IS NOT NULL THEN COALESCE(dp.pairing_status::text, 'UNPAIRED') ELSE 'UNPAIRED' END as pairing_status,
    dd.id as cursor_id,
    COALESCE(d.id, 0) as device_id,
    dd.driver_name,
    d.custom_name,
    d.site_id,
    COALESCE(s.name, '') as site_label
FROM discovered_device dd
LEFT JOIN device d ON dd.id = d.discovered_device_id
LEFT JOIN device_pairing dp ON d.id = dp.device_id
LEFT JOIN device_status ds ON d.id = ds.device_id
LEFT JOIN site s ON s.id = d.site_id
WHERE FALSE
`

type ListMinerStateSnapshotsRow struct {
	DeviceIdentifier string
	MacAddress       string
	SerialNumber     sql.NullString
	Model            sql.NullString
	Manufacturer     sql.NullString
	FirmwareVersion  sql.NullString
	WorkerName       sql.NullString
	DeviceStatus     NullDeviceStatusEnum
	StatusTimestamp  sql.NullTime
	StatusDetails    sql.NullString
	IpAddress        string
	Port             string
	UrlScheme        string
	PairingStatus    string
	CursorID         int64
	DeviceID         int64
	DriverName       string
	CustomName       sql.NullString
	SiteID           sql.NullInt64
	SiteLabel        string
}

// TYPE GENERATION STUB - This query is never executed.
// The actual list query uses a hand-written query builder in device.go
// because sqlc cannot parameterize ORDER BY direction or dynamic columns.
// This stub exists solely to generate the ListMinerStateSnapshotsRow type.
func (q *Queries) ListMinerStateSnapshots(ctx context.Context) ([]ListMinerStateSnapshotsRow, error) {
	rows, err := q.query(ctx, q.listMinerStateSnapshotsStmt, listMinerStateSnapshots)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []ListMinerStateSnapshotsRow
	for rows.Next() {
		var i ListMinerStateSnapshotsRow
		if err := rows.Scan(
			&i.DeviceIdentifier,
			&i.MacAddress,
			&i.SerialNumber,
			&i.Model,
			&i.Manufacturer,
			&i.FirmwareVersion,
			&i.WorkerName,
			&i.DeviceStatus,
			&i.StatusTimestamp,
			&i.StatusDetails,
			&i.IpAddress,
			&i.Port,
			&i.UrlScheme,
			&i.PairingStatus,
			&i.CursorID,
			&i.DeviceID,
			&i.DriverName,
			&i.CustomName,
			&i.SiteID,
			&i.SiteLabel,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Close(); err != nil {
		return nil, err
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

